def to_info_dict(self, ctx: Context) -> dict[str, t.Any]:
    info_dict = super().to_info_dict(ctx)
    commands = {}

    for name in self.list_commands(ctx):
        command = self.get_command(ctx, name)

        if command is None:
            continue

        sub_ctx = ctx._make_sub_context(command)

