import click
from click.core import Context, Group

@click.group()
def cli():
    pass

@cli.group()
def g1():
    pass

@g1.group()
def g2():
    pass

@g2.command()
@click.option('--verbose', is_flag=True)
def leaf():
    pass

# Manually replicate _resolve_context but using OLD ctx per agent1's literal spec
def resolve_old_variant(cli, ctx_args, prog_name, args):
    ctx_args['resilient_parsing'] = True
    ctx_args['validate_nesting'] = False
    with cli.make_context(prog_name, args.copy(), **ctx_args) as ctx:
        args = ctx._protected_args + ctx.args
        while args:
            command = ctx.command
            if isinstance(command, Group):
                if not command.chain:
                    name, cmd, args = command.resolve_command(ctx, args)
                    if cmd is None:
                        return ctx
                    with cmd.make_context(name, args, parent=ctx, resilient_parsing=True, validate_nesting=False) as sub_ctx:
                        args = ctx._protected_args + ctx.args   # OLD ctx per agent1 spec
                        ctx = sub_ctx
                else:
                    break
            else:
                break
    return ctx

ctx = resolve_old_variant(cli, {}, 'cli', ['g1', 'g2', 'leaf'])
print('resolved command:', ctx.command.name)
print('remaining args on ctx:', ctx.args, ctx._protected_args)
